31: /**
32:  * A trade in a CDS index, resolved for pricing.
33:  * <p>
34:  * This is the resolved form of {@link CdsIndexTrade} and is the primary input to the pricers.
35:  * Applications will typically create a {@code ResolvedCdsIndexTrade} from a {@code CdsIndexTrade}
36:  * using {@link CdsIndexTrade#resolve(ReferenceData)}.
37:  * <p>
38:  * A {@code ResolvedCdsIndexTrade} is bound to data that changes over time, such as holiday calendars.
39:  * If the data changes, such as the addition of a new holiday, the resolved form will not be updated.
40:  * Care must be taken when placing the resolved form in a cache or persistence layer.
41:  */
42: @BeanDefinition
43: public final class ResolvedCdsIndexTrade
44:     implements ResolvedTrade, ImmutableBean, Serializable {
45: 
46:   /**
47:    * The additional trade information, defaulted to an empty instance.
48:    * <p>
49:    * This allows additional information to be attached to the trade.
50:    */
51:   @PropertyDefinition(validate = "notNull", overrideGet = true)
52:   private final TradeInfo info;
53:   /**
54:    * The resolved CDS index product.
55:    * <p>
56:    * The product captures the contracted financial details of the trade.
57:    */
58:   @PropertyDefinition(validate = "notNull", overrideGet = true)
59:   private final ResolvedCdsIndex product;
60:   /**
61:    * The upfront fee of the product.
62:    * <p>
63:    * This specifies a single amount payable by the buyer to the seller
64:    * Thus the sign must be compatible with the product Pay/Receive flag.
65:    */
66:   @PropertyDefinition(get = "optional")
67:   private final Payment upfrontFee;
68: 
69:   //-------------------------------------------------------------------------
70:   @ImmutableDefaults
71:   private static void applyDefaults(Builder builder) {
72:     builder.info = TradeInfo.empty();
73:   }
74: 
75:   //-------------------------------------------------------------------------
76:   /**
77:    * Reduce this instance to {@code ResolvedCdsTrade}.
78:    * <p>
79:    * The resultant object is used for pricing CDS index trades under the homogeneous pool assumption on constituent  
80:    * credit curves. 
81:    * 
82:    * @return the CDS trade
83:    */
84:   public ResolvedCdsTrade toSingleNameCds() {
85:     return ResolvedCdsTrade.builder()
86:         .product(product.toSingleNameCds())
87:         .info(info)
88:         .upfrontFee(upfrontFee)
89:         .build();
90:   }
