175:   //-------------------------------------------------------------------------
176:   /**
177:    * Obtains the effective start date from the step-in date. 
178:    * 
179:    * @param stepinDate  the step-in date
180:    * @return the effective start date
181:    */
182:   public LocalDate calculateEffectiveStartDate(LocalDate stepinDate) {
183:     LocalDate startDate = stepinDate.isAfter(getAccrualStartDate()) ? stepinDate : getAccrualStartDate();
184:     return protectionStart.isBeginning() ? startDate.minusDays(1) : startDate;
185:   }
186: 
187:   /**
188:    * Calculates the settlement date from the valuation date.
189:    * 
190:    * @param valuationDate  the valuation date
191:    * @param refData  the reference data to use
192:    * @return the settlement date
193:    */
194:   public LocalDate calculateSettlementDateFromValuation(LocalDate valuationDate, ReferenceData refData) {
195:     return settlementDateOffset.adjust(valuationDate, refData);
196:   }
197: 
198:   //-------------------------------------------------------------------------
199:   /**
200:    * Finds the period that contains the specified date.
201:    * <p>
202:    * The search is performed using unadjusted dates.
203:    * 
204:    * @param date  the date to find the period for
205:    * @return the period, empty if not found
206:    * @throws IllegalArgumentException if more than one period matches
207:    */
208:   public Optional<CreditCouponPaymentPeriod> findPeriod(LocalDate date) {
209:     return paymentPeriods.stream()
210:         .filter(p -> p.contains(date))
211:         .reduce(ensureOnlyOne());
212:   }
213: 
214:   /**
215:    * Calculates the accrued premium per fractional spread for unit notional.
216:    * 
217:    * @param stepinDate  the step-in date
218:    * @return the accrued year fraction
219:    */
220:   public double accruedYearFraction(LocalDate stepinDate) {
221:     if (stepinDate.isBefore(getAccrualStartDate())) {
222:       return 0d;
223:     }
224:     if (stepinDate.isEqual(getAccrualEndDate())) {
225:       return paymentPeriods.get(paymentPeriods.size() - 1).getYearFraction();
226:     }
227:     CreditCouponPaymentPeriod period = findPeriod(stepinDate)
228:         .orElseThrow(() -> new IllegalArgumentException("Date outside range"));
229:     return dayCount.relativeYearFraction(period.getStartDate(), stepinDate);
230:   }
