30: /**
31:  * Perform calculations on a single {@code CdsIndexTrade} for each of a set of scenarios.
32:  * <p>
33:  * An instance of {@link CreditRatesMarketDataLookup} must be specified.
34:  * The supported built-in measures are:
35:  * <ul>
36:  *   <li>{@linkplain Measures#PRESENT_VALUE Present value}
37:  *   <li>{@linkplain Measures#PV01_CALIBRATED_SUM PV01 calibrated sum on rate curves}
38:  *   <li>{@linkplain Measures#PV01_CALIBRATED_BUCKETED PV01 calibrated bucketed on rate curves}
39:  *   <li>{@linkplain Measures#PV01_MARKET_QUOTE_SUM PV01 market quote sum on rate curves}
40:  *   <li>{@linkplain Measures#PV01_MARKET_QUOTE_BUCKETED PV01 market quote bucketed on rate curves}
41:  *   <li>{@linkplain Measures#UNIT_PRICE Unit price}
42:  *   <li>{@linkplain CreditMeasures#PRINCIPAL principal}
43:  *   <li>{@linkplain CreditMeasures#IR01_CALIBRATED_PARALLEL IR01 calibrated parallel}
44:  *   <li>{@linkplain CreditMeasures#IR01_CALIBRATED_BUCKETED IR01 calibrated bucketed}
45:  *   <li>{@linkplain CreditMeasures#IR01_MARKET_QUOTE_PARALLEL IR01 market quote parallel}
46:  *   <li>{@linkplain CreditMeasures#IR01_MARKET_QUOTE_BUCKETED IR01 market quote bucketed}
47:  *   <li>{@linkplain CreditMeasures#CS01_PARALLEL CS01 parallel}
48:  *   <li>{@linkplain CreditMeasures#CS01_BUCKETED CS01 bucketed}
49:  *   <li>{@linkplain CreditMeasures#RECOVERY01 recovery01}
50:  *   <li>{@linkplain CreditMeasures#JUMP_TO_DEFAULT jump to default}
51:  *   <li>{@linkplain CreditMeasures#EXPECTED_LOSS expected loss}
52:  * </ul>
53:  * <p>
54:  * The "natural" currency is the currency of the CDS index, which is limited to be single-currency.
55:  */
56: public class CdsIndexTradeCalculationFunction
57:     implements CalculationFunction<CdsIndexTrade> {
58: 
59:   /**
60:    * The calculations by measure.
61:    */
62:   private static final ImmutableMap<Measure, SingleMeasureCalculation> CALCULATORS =
63:       ImmutableMap.<Measure, SingleMeasureCalculation>builder()
64:           .put(Measures.PRESENT_VALUE, CdsIndexMeasureCalculations.DEFAULT::presentValue)
65:           .put(Measures.PV01_CALIBRATED_SUM, CdsIndexMeasureCalculations.DEFAULT::pv01CalibratedSum)
66:           .put(Measures.PV01_CALIBRATED_BUCKETED, CdsIndexMeasureCalculations.DEFAULT::pv01CalibratedBucketed)
67:           .put(Measures.PV01_MARKET_QUOTE_SUM, CdsIndexMeasureCalculations.DEFAULT::pv01MarketQuoteSum)
68:           .put(Measures.PV01_MARKET_QUOTE_BUCKETED, CdsIndexMeasureCalculations.DEFAULT::pv01MarketQuoteBucketed)
69:           .put(Measures.UNIT_PRICE, CdsIndexMeasureCalculations.DEFAULT::unitPrice)
70:           .put(CreditMeasures.PRINCIPAL, CdsIndexMeasureCalculations.DEFAULT::principal)
71:           .put(CreditMeasures.IR01_CALIBRATED_PARALLEL, CdsIndexMeasureCalculations.DEFAULT::ir01CalibratedParallel)
72:           .put(CreditMeasures.IR01_CALIBRATED_BUCKETED, CdsIndexMeasureCalculations.DEFAULT::ir01CalibratedBucketed)
73:           .put(CreditMeasures.IR01_MARKET_QUOTE_PARALLEL, CdsIndexMeasureCalculations.DEFAULT::ir01MarketQuoteParallel)
74:           .put(CreditMeasures.IR01_MARKET_QUOTE_BUCKETED, CdsIndexMeasureCalculations.DEFAULT::ir01MarketQuoteBucketed)
75:           .put(CreditMeasures.CS01_PARALLEL, CdsIndexMeasureCalculations.DEFAULT::cs01Parallel)
76:           .put(CreditMeasures.CS01_BUCKETED, CdsIndexMeasureCalculations.DEFAULT::cs01Bucketed)
77:           .put(CreditMeasures.RECOVERY01, CdsIndexMeasureCalculations.DEFAULT::recovery01)
78:           .put(CreditMeasures.JUMP_TO_DEFAULT, CdsIndexMeasureCalculations.DEFAULT::jumpToDefault)
79:           .put(CreditMeasures.EXPECTED_LOSS, CdsIndexMeasureCalculations.DEFAULT::expectedLoss)
80:           .put(Measures.RESOLVED_TARGET, (rt, smd, rd) -> rt)
81:           .build();
82: 
83:   private static final ImmutableSet<Measure> MEASURES = CALCULATORS.keySet();
84: 
85:   /**
86:    * Creates an instance.
87:    */
88:   public CdsIndexTradeCalculationFunction() {
89:   }
90: 
91:   //-------------------------------------------------------------------------
92:   @Override
93:   public Class<CdsIndexTrade> targetType() {
94:     return CdsIndexTrade.class;
95:   }
