        .buySell(buySell)
        .cdsIndexId(cdsIndexId)
        .legalEntityIds(legalEntityIds)
        .protectionStart(protectionStart)
        .paymentOnDefault(paymentOnDefault)
        .paymentPeriods(paymentPeriods)
        .protectionEndDate(lastPeriod.getEndDate())
